const express = require('express');
const multer = require('multer');
const path = require('path');
const crypto = require('crypto');
const fs = require('fs');

const app = express();

// Define secure upload directory outside webroot
const UPLOAD_DIR = path.resolve(__dirname, '..', 'secure_uploads');

// Ensure upload directory exists with restricted permissions
if (!fs.existsSync(UPLOAD_DIR)) {
  fs.mkdirSync(UPLOAD_DIR, { recursive: true, mode: 0o700 });
}

// Whitelist of allowed MIME types
const ALLOWED_MIME_TYPES = [
  'image/jpeg',
  'image/png',
  'image/gif',
  'application/pdf'
];

// Max file size: 5MB
const MAX_FILE_SIZE = 5 * 1024 * 1024;

// Configure multer with secure settings
const storage = multer.diskStorage({
  destination: function (req, file, cb) {
    // CRITICAL: Always use hardcoded, absolute path
    // Never allow user input to influence destination
    cb(null, UPLOAD_DIR);
  },
  filename: function (req, file, cb) {
    // SECURE: Generate cryptographically random filename
    // Completely discard user-supplied filename
    const uniqueSuffix = crypto.randomBytes(16).toString('hex');
    const ext = path.extname(file.originalname).toLowerCase();

    // Validate extension is safe
    const safeExtensions = ['.jpg', '.jpeg', '.png', '.gif', '.pdf'];
    if (!safeExtensions.includes(ext)) {
      return cb(new Error('Invalid file extension'));
    }

    const safeFilename = `${uniqueSuffix}${ext}`;

    // CRITICAL: Validate final path doesn't contain traversal
    const finalPath = path.join(UPLOAD_DIR, safeFilename);
    const normalizedPath = path.normalize(finalPath);

    if (!normalizedPath.startsWith(UPLOAD_DIR)) {
      return cb(new Error('Path traversal attempt detected'));
    }

    cb(null, safeFilename);
  }
});

// File filter for MIME type validation
const fileFilter = (req, file, cb) => {
  if (ALLOWED_MIME_TYPES.includes(file.mimetype)) {
    cb(null, true);
  } else {
    cb(new Error(`Invalid file type. Allowed: ${ALLOWED_MIME_TYPES.join(', ')}`), false);
  }
};

const upload = multer({
  storage: storage,
  fileFilter: fileFilter,
  limits: {
    fileSize: MAX_FILE_SIZE,
    files: 1 // Only one file per request
  }
});

// Upload endpoint with additional validation
app.post('/api/upload', upload.single('file'), (req, res) => {
  if (!req.file) {
    return res.status(400).json({ error: 'No file uploaded' });
  }

  // Log upload for audit trail
  console.log(`[UPLOAD] User: ${req.user?.id || 'anonymous'}, File: ${req.file.filename}, Size: ${req.file.size}`);

  // Store metadata in database (not shown)
  // Associate uploaded file with user and generate secure access URL

  res.json({
    success: true,
    fileId: req.file.filename,
    size: req.file.size,
    url: `/api/files/${req.file.filename}` // Serve via controlled endpoint
  });
});

// Error handling middleware
app.use((error, req, res, next) => {
  if (error instanceof multer.MulterError) {
    if (error.code === 'LIMIT_FILE_SIZE') {
      return res.status(400).json({ error: 'File too large (max 5MB)' });
    }
    return res.status(400).json({ error: `Upload error: ${error.message}` });
  }

  if (error) {
    console.error('[UPLOAD ERROR]', error);
    return res.status(500).json({ error: 'Upload failed' });
  }

  next();
});

app.listen(3000, () => console.log('Server running on port 3000'));

const express = require('express');
const AWS = require('aws-sdk');
const crypto = require('crypto');

const app = express();

// Configure AWS S3 with least-privilege IAM role
const s3 = new AWS.S3({
  region: process.env.AWS_REGION || 'us-east-1',
  signatureVersion: 'v4'
});

const BUCKET_NAME = process.env.S3_UPLOAD_BUCKET;
const ALLOWED_CONTENT_TYPES = [
  'image/jpeg',
  'image/png',
  'image/gif',
  'application/pdf'
];
const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB

/**
 * Generate pre-signed URL for direct browser-to-S3 upload
 * This bypasses application server entirely, preventing path traversal
 */
app.post('/api/upload/presigned-url', async (req, res) => {
  const { fileName, contentType } = req.body;

  // Validate content type
  if (!ALLOWED_CONTENT_TYPES.includes(contentType)) {
    return res.status(400).json({ 
      error: `Invalid content type. Allowed: ${ALLOWED_CONTENT_TYPES.join(', ')}` 
    });
  }

  // Generate secure S3 key (completely ignore user filename)
  const fileExtension = contentType.split('/')[1];
  const uniqueKey = `uploads/${crypto.randomUUID()}.${fileExtension}`;

  // S3 pre-signed POST parameters
  const params = {
    Bucket: BUCKET_NAME,
    Key: uniqueKey,
    Expires: 300, // URL expires in 5 minutes
    ContentType: contentType,
    Conditions: [
      ['content-length-range', 0, MAX_FILE_SIZE],
      ['eq', '$Content-Type', contentType]
    ],
    Fields: {
      'Content-Type': contentType,
      'x-amz-server-side-encryption': 'AES256',
      'x-amz-meta-uploaded-by': req.user?.id || 'anonymous'
    }
  };

  try {
    // Generate pre-signed POST URL
    const presignedPost = s3.createPresignedPost(params);

    // Return to client for direct upload
    res.json({
      uploadUrl: presignedPost.url,
      fields: presignedPost.fields,
      fileKey: uniqueKey,
      expiresIn: 300
    });

  } catch (error) {
    console.error('[S3 ERROR]', error);
    res.status(500).json({ error: 'Failed to generate upload URL' });
  }
});

/**
 * Generate pre-signed URL for secure file download
 */
app.get('/api/files/:fileKey', async (req, res) => {
  const { fileKey } = req.params;

  // CRITICAL: Validate fileKey format (prevent path traversal in S3)
  if (!fileKey.match(/^uploads\/[a-f0-9-]+\.(jpg|jpeg|png|gif|pdf)$/i)) {
    return res.status(400).json({ error: 'Invalid file key' });
  }

  const params = {
    Bucket: BUCKET_NAME,
    Key: fileKey,
    Expires: 3600 // Download URL valid for 1 hour
  };

  try {
    const downloadUrl = await s3.getSignedUrlPromise('getObject', params);
    res.json({ downloadUrl });
  } catch (error) {
    console.error('[S3 ERROR]', error);
    res.status(404).json({ error: 'File not found' });
  }
});

// Client-side upload example (JavaScript)
